refentry.refsect1:
  &reftitle.examples;

   Zookeeper::dispatch example #1

     Dispatch callbacks manually.



<?php
$client = new Zookeeper();
$client->connect('localhost:2181');
$client->get('/zookeeper', function() {
    echo "Callback was called".PHP_EOL;
});
while(true) {
    sleep(1);
    Zookeeper::dispatch();
}
?>





   Zookeeper::dispatch example #2

     Declare ticks.



<?php
declare(ticks=1);

$client = new Zookeeper();
$client->connect('localhost:2181');
$client->get('/zookeeper', function() {
    echo "Callback was called".PHP_EOL;
});
while(true) {
    sleep(1);
}
?>
